f, memory = d1$cumulativerate # this creates the new parameter: the rate of right hands so far in log-odds ) stan_model &lt;- &quot; // The input (data) for the model. n of trials and h for (right and left) hand data { int&lt;lower=1&gt; n; array[n] int h; vector[n] memory; // here we add the new variable between 0.01 and .99 } // The parameters accepted by the model. parameters { real bias; // how likely is the agent to pick right when the previous rate has no information (50-50)? real beta; // how strongly is previous rate impacting the decision? } // The model to be estimated. model { // priors target += normal_lpdf(bias | 0, .3); target += normal_lpdf(beta | 0, .5); // model target += bernoulli_logit_lpmf(h | bias + beta * logit(memory)); } generated quantities { // Generate prior samples for Prior-Posterior Update checks real bias_prior = normal_rng(0, 0.3); real beta_prior = normal_rng(0, 0.5); } &quot; write_stan_file( stan_model, dir = &quot;stan/&quot;, basename = &quot;04_MemoryBernoulli.stan&quot;) ## [1] &quot;/Users/au209589/Dropbox/Teaching/AdvancedCognitiveModeling23_book/stan/04_MemoryBernoulli.stan&quot; ## Specify where the model is file &lt;- here(&quot;stan&quot;,&quot;04_MemoryBernoulli.stan&quot;) # File path for saved model model_file_memory &lt;- here(&quot;simmodels&quot;, &quot;04_MemoryBernoulli.rds&quot;) # Check if we need to rerun the simulation if (regenerate_simulations || !file.exists(model_file_memory)) { # Compile the model mod_memory &lt;- cmdstan_model(file) # The following command calls Stan with specific options. samples_memory &lt;- mod_memory$sample( data = data_memory, seed = 123, chains = 2, parallel_chains = 2, threads_per_chain = 1, iter_warmup = 1000, iter_sampling = 1000, refresh = 0, max_treedepth = 20, adapt_delta = 0.99, ) # Save the fitted model samples_memory$save_object(file = model_file_memory) cat(&quot;Generated new model fit and saved to&quot;, model_file_memory, &quot;
