parameters target += gamma_lpdf(alpha_prior | 2, 1); target += gamma_lpdf(beta_prior | 2, 1); // Agent&#39;s choices follow current rate estimates for(t in 1:n) { target += bernoulli_lpmf(h[t] | rate[t]); } } generated quantities { // We strictly reserve posterior predictive checks for Chapter 5. // Here, we just calculate the initial expected rate for reference. real initial_rate = alpha_prior / (alpha_prior + beta_prior); } &quot; write_stan_file( stan_model, dir = &quot;stan/&quot;, basename = &quot;04_BayesianMemory.stan&quot;) ## [1] &quot;/Users/au209589/Dropbox/Teaching/AdvancedCognitiveModeling23_book/stan/04_BayesianMemory.stan&quot; ## Specify where the model is file &lt;- here(&quot;stan&quot;,&quot;04_BayesianMemory.stan&quot;) # File path for saved model model_file &lt;- here(&quot;simmodels&quot;,&quot;04_BayesianMemory.rds&quot;) # Check if we need to rerun the simulation if (regenerate_simulations || !file.exists(model_file)) { # Compile the model mod &lt;- cmdstan_model(file) # The following command calls Stan with specific options. samples_memory_bayes &lt;- mod$sample( data = data, seed = 123, chains = 1, parallel_chains = 2, threads_per_chain = 1, iter_warmup = 1000, iter_sampling = 1000, refresh = 0, max_treedepth = 20, adapt_delta = 0.99, ) # Save the fitted model samples_memory_bayes$save_object(file = model_file) cat(&quot;Generated new model fit and saved to&quot;, model_file, &quot;
