= seq(120), choices = data$other) # Plot the evolution of rate estimates ggplot(rate_summary, aes(x = trial)) + geom_ribbon(aes(ymin = lower, ymax = upper), alpha = 0.2) + geom_line(aes(y = mean_rate), color = &quot;blue&quot;) + # Add true data points geom_line(data = plot_data, aes(x = trial, y = choices), color = &quot;orange&quot;, alpha = 0.5) + theme_classic() + labs(title = &quot;Evolution of Rate Estimates&quot;, x = &quot;Trial&quot;, y = &quot;Rate&quot;, subtitle = &quot;Blue line: posterior mean, Gray band: 95% CI&quot;) + ylim(0, 1) # Let&#39;s also look at the correlation between alpha and beta parameters ggplot(draws_df) + geom_point(aes(alpha_prior, beta_prior), alpha = 0.1) + theme_classic() + labs(title = &quot;Correlation between Alpha and Beta Parameters&quot;, x = &quot;Alpha&quot;, y = &quot;Beta&quot;) 5.9 Relationship to Rescorla-Wagner The Rescorla-Wagner model of learning—which drives the Reinforcement Learning agents we will build in in a later chapter follows the form: \[V_{t+1} = V_{t} + \alpha (R_{t} - V_{t})\] where: \(V_{t}\) is the current Value estimate (in our code: memory[t]). \(\alpha\) is the Learning Rate (in our code: forgetting). \(R_{t}\) is the Reward or Outcome (in our code: other[t]). \((R_{t} - V_{t})\) is the Prediction Error. Our memory model with a forgetting parameter follows a very similar structure:\[	ext{memory}_{t+1} = (1 - 	ext{forgetting}) 	imes 	ext{memory}_{t} + 	ext{forgetting} 	imes 	ext{outcome}_{t}\]If we expand this, we can see it is mathematically identical to the Rescorla-Wagner update rule:\[ egin{aligned} 	ext{memory}_{t+1} &amp;= 	ext{memory}_{t} - 	ext{forgetting} 	imes 	ext{memory}_{t} + 	ext{forgetting} 	imes 	ext{outcome}_{t} \ 	ext{memory}_{t+1} &amp;= 	ext{memory}_{t} + 	ext{forgetting} 	imes (	ext{outcome}_{t} - 	ext{memory}_{t}) \end{aligned}\] This reveals that our “exponential forgetting” memory model is actually a standard Reinforcement Learning agent with a big fake moustache. The forgetting parameter dictates how quickly the agent updates their beliefs (value estimate) based on new prediction errors. 5.9.1 Connection to Kalman Filters Our memory model updates beliefs about the probability of right-hand choices using a weighted average of past observations. This is conceptually similar to how a Kalman filter works, though simpler: Kalman filters maintain both an estimate and uncertainty about that estimate They optimally weight new evidence based on relative uncertainty Our forgetting model uses a fixed weighting scheme (1/trial or the forgetting parameter) The Bayesian Agent (04_BayesianMemory.stan) captures uncertainty via the Beta distribution, similar in spirit but simpler than a Kalman filter. 5.9.2 Connection to Hierarchical Gaussian Filter (HGF) The HGF extends these ideas by: Tracking beliefs at multiple levels Allowing learning rates to vary over time Explicitly modeling environmental volatility Our model could be seen as the simplest case of an HGF where: We only track one level (probability of right-hand choice) Have a fixed learning rate (forgetting parameter) Don’t explicitly model environmental volatility 5.9.3 Implications for Model Development Understanding these relationships helps us think about how models relate to each other and to extend our model: We could add uncertainty estimates to get Kalman-like behavior We could make the forgetting parameter dynamic to capture changing learning rates We could add multiple levels to track both immediate probabilities and longer-term trends Each extension would make the model more flexible but also more complex to fit to data. The choice depends on our specific research questions and available data. 5.10 Conclusion: Estimating Parameters and Exploring Memory This chapter marked a crucial transition from simulating models with known parameters to the core task of parameter estimation: inferring plausible parameter values from observed data using Bayesian inference and Stan. We learned how to: Specify Bayesian models in Stan, defining data, parameters, priors, and likelihoods. Fit models using cmdstanr to obtain posterior distributions for parameters like choice bias (theta). Utilize transformations like log-odds for computational benefits and flexible prior specification. Validate our fitting procedure through parameter recovery, ensuring our models can retrieve known values from simulated data. Implement different cognitive models for history-dependent choice, exploring various ways to represent memory: as an external predictor, an internal updating state, incorporating exponential forgetting (linking to Reinforcement Learning principles), and even as a fully Bayesian belief update. Recognize connections between these models and broader frameworks like Kalman filters and HGF. By fitting these models, we moved beyond simply describing behavior (like the cumulative rates in Chapter 3) to quantifying underlying latent parameters (like bias, beta, forgetting). However, a single fit to a single simulated dataset is only a preliminary sanity check — the equivalent of flipping a coin once to check if it’s fair. It does not tell us whether the model behaves well across a wide range of parameter values, whether our credible intervals are correctly calibrated, or whether the fitted model can actually reproduce the patterns in the data. Coming up in Chapter 5: We take the Stan models built in this chapter and subject them to a four-phase validation battery before they are allowed near real human data: Prior Predictive Check — do the priors allow only cognitively plausible behavior? Parameter Recovery — does the model find the right answer across many simulated datasets and noise levels? Simulation-Based Calibration (SBC) — are our posterior intervals actually calibrated (does a 95% CI contain the truth 95% of the time)? Posterior Predictive Check — does the fitted model reproduce key patterns in the observed data? Only after passing all four tests does a model earn the right to touch real empirical data.

 Chapter 9 Mixture Models 📍 Where we are in the Bayesian modeling workflow: Chs. 1–7 modelled behaviour as arising from a single cognitive process per agent. This chapter relaxes that assumption: behaviour can be a weighted mixture of distinct processes (e.g., deliberate strategy and attentional lapses). Mixture models extend the toolkit from Ch. 6 (hierarchical structures) and Ch. 7 (model comparison via LOO) to this new model class. The key new challenge is that discrete latent variables — which process generated this trial? — cannot be sampled by HMC and must be analytically integrated out before any Stan code is written. The full course roadmap is in Ch. 1, Section “The Course Roadmap”. When we model human cognition and behavior, people do not always follow a single, consistent strategy. A participant in a matching-pennies game might sometimes carefully exploit a detected pattern in the opponent’s behavior, and other times respond essentially at random when attention lapses. Traditional single-process models are structurally misspecified when this is the case: they attribute lapse-driven variance to the strategic parameter, inflating its uncertainty and biasing its location. Mixture models provide an elegant and principled solution. Rather than assuming behavior reflects one cognitive process, they represent observations as draws from a weighted combination of component distributions, each corresponding to a distinct process. This reframes the question addressed in Chapter 7 — which model is correct? — into a richer question: how much does each process contribute, and for which observations? Because each component must be marginalized analytically before writing Stan code, mixture models also serve as a concrete introduction to a class of computational constraint that applies broadly: discrete parameters cannot be sampled by HMC and must be integrated out. Mastering this principle is prerequisite for hidden Markov models, contamination models, and finite mixture clusters. 9.0.1 Learning Objectives After completing this chapter you will be able to: Specify a mixture model as a marginalized sum of component log-likelihoods and articulate why marginalization is required in Stan. Identify and correct the vectorisation error that makes the mixture likelihood computationally wrong when component densities are applied to arrays. Validate a mixture model with SBC, extracting both calibration diagnostics and parameter recovery from the same simulation bank. Characterize the likelihood-level identifiability constraint that limits what binary choice data can tell us about mixture parameters, and visualise the posterior aliasing manifold. Extend the single-agent model to a hierarchical mixture model with a non-centred parameterisation. 9.1 Motivation: When are Mixtures Visible? Before developing the mathematics, consider a concrete case where a mixture is visually transparent. In many response-time tasks, a participant sometimes deliberates carefully (producing a log-normal RT distribution) and sometimes responds inattentively (producing a roughly uniform RT distribution). The resulting marginal distribution is a weighted blend. set.seed(8) n_obs &lt;- 500 pi_delib &lt;- 0.80 # 80 % deliberate mu_log &lt;- 6.2 # mean of log(RT), deliberate process ≈ 500 ms sigma_log &lt;- 0.20 min_lapse &lt;- 200 max_lapse &lt;- 2000 component &lt;- rbinom(n_obs, 1, pi_delib) # 1 = deliberate, 0 = lapse rt_data &lt;- tibble( rt = ifelse(component == 1, rlnorm(n_obs, mu_log, sigma_log), runif(n_obs, min_lapse, max_lapse)), log_rt = log(rt), process = ifelse(component == 1, &quot;Deliberate&quot;, &quot;Lapse&quot;) ) # RT scale p1 &lt;- ggplot(rt_data, aes(x = rt)) + geom_histogram(aes(y = after_stat(density)), bins = 50, fill = &quot;grey80&quot;, colour = &quot;white&quot;) + geom_density(aes(colour = process, fill = process), data = rt_data |&gt; filter(process == &quot;Deliberate&quot;), alpha = 0.25, linewidth = 0.9) + geom_segment( aes(x = min_lapse, xend = max_lapse, y = 1 / (max_lapse - min_lapse), yend = 1 / (max_lapse - min_lapse), colour = &quot;Lapse&quot;), linewidth = 1.2 ) + scale_colour_manual(values = c(Deliberate = &quot;#2166AC&quot;, Lapse = &quot;#D6604D&quot;), name = NULL) + scale_fill_manual(values = c(Deliberate = &quot;#2166AC&quot;, Lapse = &quot;#D6604D&quot;), name = NULL, guide = &quot;none&quot;) + coord_cartesian(xlim = c(0, 2000)) + labs(title = &quot;Reaction-time distribution&quot;, subtitle = &quot;A mixture of deliberate (log-normal) and lapse (uniform) processes&quot;, x = &quot;RT (ms)&quot;, y = &quot;Density&quot;) + theme(legend.position = &quot;top&quot;) # Log-RT scale p2 &lt;- ggplot(rt_data, aes(x = log_rt)) + geom_histogram(aes(y = after_stat(density)), bins = 50, fill = &quot;grey80&quot;, colour = &quot;white&quot;) + geom_density(aes(colour = process, fill = process), data = rt_data |&gt; filter(process == &quot;Deliberate&quot;), alpha = 0.25, linewidth = 0.9) + scale_colour_manual(values = c(Deliberate = &quot;#2166AC&quot;), name = NULL) + scale_fill_manual(values = c(Deliberate = &quot;#2166AC&quot;), name = NULL) + labs(title = &quot;Log-RT distribution&quot;, subtitle = &quot;Log transformation clarifies the deliberate component&quot;, x = &quot;log RT&quot;, y = &quot;Density&quot;) + theme(legend.position = &quot;top&quot;) p1 / p2 In the RT case, the two components have genuinely different support structures — the lapse process contributes probability mass across a 1,800 ms window, while the deliberate process is tightly concentrated. Each observation therefore carries real information about which component generated it, so the mixture is well-identified from the marginal distribution alone. We will return to this point in Section 6. For binary choice data, the identifiability picture is dramatically different. 9.2 Theoretical Framework 9.2.1 The Mixture Density A \(K\)-component mixture model assigns the following marginal density (or mass function) to each observation \(y_i\): \[ p(y_i) = \sum_{k=1}^{K} \pi_k \, p_k(y_i \mid 	heta_k), \qquad \pi_k \ge 0, \quad \sum_{k=1}^{K} \pi_k = 1. 	ag{1} \] Each \(p_k(\cdot \mid 	heta_k)\) is a component distribution with its own parameter vector \(	heta_k\), and \(\pi_k\) is the corresponding mixing weight. Given independent observations, the joint likelihood is \[ p(y \mid \pi, 	heta) = \prod_{i=1}^{n} \sum_{k=1}^{K} \pi_k \, p_k(y_i \mid 	heta_k). 	ag{2} \] The log-likelihood therefore contains a sum inside a log — this cannot be factored into independent additive contributions per component, which makes mixture models more computationally demanding than standard regression. 9.2.2 The Latent-Variable Augmentation An equivalent and conceptually useful representation introduces a latent component indicator \(z_i \in \{1, \ldots, K\}\): \[ z_i \sim 	ext{Categorical}( oldsymbol{\pi}), \qquad y_i \mid z_i = k \sim p_k(y_i \mid 	heta_k). 	ag{3} \] If we could observe \(z_i\) the model would decompose into \(K\) separate standard likelihoods. Unfortunately \(z_i\) is unobserved, so we sum (integrate) over all possible component assignments to recover equation (1). This is the marginalisation step. 9.2.3 Why Stan Requires Marginalisation Stan’s Hamiltonian Monte Carlo sampler operates on a continuous, differentiable log posterior. It cannot directly sample discrete random variables such as \(z_i\). Marginalising \(z_i\) before writing any Stan code is not optional; it is a structural requirement. The joint model \((z_i, y_i)\) must be reduced to the marginal model \(p(y_i)\) expressed entirely through continuous parameters. Stan provides log_mix() as a numerically stable implementation of the per-observation mixture contribution: \[ 	exttt{log\_mix}(\pi, \ell_1, \ell_2) \;=\; \log\! igl[\pi \, e^{\ell_1} + (1-\pi) \, e^{\ell_2} igr], 	ag{4} \] where \(\ell_1 = \log p_1(y_i \mid 	heta_1)\) and \(\ell_2 = \log p_2(y_i \mid 	heta_2)\). 9.2.4 Our Running Model: Bias–Noise Mixture for Binary Choices We model binary choices as a mixture of a biased process and a random process: \[ y_i \sim (1-\pi)\,	ext{Bernoulli}(	heta) + \pi\,	ext{Bernoulli}(0.5), 	ag{5} \] where \(	heta = 	ext{logit}^{-1}(\alpha)\) is the probability of choosing “right” under the biased process, and \(\pi = 	ext{logit}^{-1}(
u)\) is the probability that any given trial is generated by the random process. Both are modelled on the logit scale: \[ \alpha \sim 	ext{Normal}(0,\, 1), \qquad 
u \sim 	ext{Normal}(-1,\, 1). 	ag{6} \] The centring of \(
u\) at \(-1\) weakly favours noise below 50 %, reflecting the prior belief that most trials are deliberate. 9.3 Prior Predictive Check Before writing any Stan code, we simulate from the prior to verify that the implied distribution over observable behaviour is scientifically plausible. Why check priors before writing Stan code? A prior that assigns &gt;30% mass to noise rates above π = 0.5 means we expect most trials to be random — a scientifically implausible starting point that would corrupt the posterior before data are ever observed. set.seed(8) n_prior &lt;- 10000 prior_df &lt;- tibble( alpha = rnorm(n_prior, 0, 1), nu = rnorm(n_prior, -1, 1), theta = plogis(alpha), pi_noise = plogis(nu), # Marginalised effective probability of choosing &quot;right&quot; theta_eff = (1 - plogis(nu)) * plogis(alpha) + 0.5 * plogis(nu) ) p_bias &lt;- ggplot(prior_df, aes(x = theta)) + geom_histogram(aes(y = after_stat(density)), bins = 60, fill = &quot;#2166AC&quot;, alpha = 0.7) + labs(title = expression(&quot;Prior on &quot; * theta * &quot; (bias)&quot;), subtitle = &quot;Normal(0, 1) on logit scale&quot;, x = expression(theta), y = &quot;Density&quot;) + scale_x_continuous(limits = c(0, 1)) p_noise &lt;- ggplot(prior_df, aes(x = pi_noise)) + geom_histogram(aes(y = after_stat(density)), bins = 60, fill = &quot;#D6604D&quot;, alpha = 0.7) + labs(title = expression(&quot;Prior on &quot; * pi * &quot; (noise weight)&quot;), subtitle = &quot;Normal(-1, 1) on logit scale&quot;, x = expression(pi), y = &quot;Density&quot;) + scale_x_continuous(limits = c(0, 1)) p_eff &lt;- ggplot(prior_df, aes(x = theta_eff)) + geom_histogram(aes(y = after_stat(density)), bins = 60, fill = &quot;grey40&quot;, alpha = 0.7) + geom_vline(xintercept = 0.5, linetype = &quot;dashed&quot;, colour = &quot;black&quot;) + labs(title = expression(&quot;Prior on &quot; * theta[eff] * &quot; = (1-&quot; * pi * &quot;)&quot; * theta * &quot; + 0.5&quot; * pi), subtitle = &quot;Marginalised effective choice probability&quot;, x = expression(theta[eff]), y = &quot;Density&quot;) + scale_x_continuous(limits = c(0, 1)) (p_bias + p_noise) / p_eff The prior on \(	heta\) is diffuse but centred at 0.5, spanning the full plausible range of biases. The noise prior concentrates most mass below \(\pi = 0.5\), reflecting the scientific expectation that participants are mostly deliberate. The marginalised effective probability \(	heta_{	ext{eff}}\) is correspondingly diffuse but slightly shrunk toward 0.5. These are all scientifically defensible starting points. Note: If you found that the noise prior placed more than ≈ 30 % of its mass above \(\pi = 0.4\), that would indicate the prior is too permissive. This is the value of checking the prior predictive before fitting: it costs nothing and can prevent days of debugging a misspecified model. 9.4 Stan Implementation: Single-Agent Model 9.4.1 A Critical Vectorisation Trap The Stan code in the original version of this chapter contained a subtle but consequential error. It called: target += log_sum_exp( log(pi) + bernoulli_logit_lpmf(h | 0), log(1-pi) + bernoulli_logit_lpmf(h | bias) ); where h is a vector. bernoulli_logit_lpmf(h | 0) with a vector h returns the scalar \(\sum_i \log p_1(y_i)\) — the joint log-probability of all observations under component 1. log_sum_exp then computes: \[ \log\!\Bigl[\pi \prod_i p_1(y_i) \;+\; (1-\pi) \prod_i p_2(y_i)\Bigr]. \] This is not a mixture model. It is a model in which all \(n\) observations simultaneously come from one component or the other — equivalent to a global discrete model-selection variable, not per-trial latent class assignment. The correct log-likelihood is: \[ \sum_{i=1}^{n} \log\!\Bigl[\pi \, p_1(y_i) + (1-\pi) \, p_2(y_i)\Bigr], \] which requires iterating log_mix() inside a loop over observations. 9.4.2 The Correct Stan Model Why must discrete parameters be marginalised? Stan’s HMC sampler requires a continuous, differentiable log-posterior. The latent component indicator z_i is discrete. Marginalising it — summing over its two possible values inside log_mix() — converts the model into a purely continuous problem that HMC can handle. single_mixture_stan &lt;- &quot; data { int&lt;lower=1&gt; n; array[n] int&lt;lower=0, upper=1&gt; h; } parameters { real alpha; // logit-scale bias (biased component) real nu; // logit-scale mixing weight (random component) } model { real noise_p = inv_logit(nu); target += normal_lpdf(alpha | 0, 1); target += normal_lpdf(nu | -1, 1); // Correct: one log_mix call per observation. // logit(0.5) = 0.0, so bernoulli_logit_lpmf(h[i] | 0.0) is used for // the random component — keeping both calls on the logit scale for // consistency and to avoid an implicit probability-to-logit conversion. for (i in 1:n) target += log_mix(noise_p, bernoulli_logit_lpmf(h[i] | 0.0), // random component bernoulli_logit_lpmf(h[i] | alpha)); // biased component } generated quantities { real&lt;lower=0, upper=1&gt; theta = inv_logit(alpha); // bias, probability scale real&lt;lower=0, upper=1&gt; pi_hat = inv_logit(nu); // noise weight, prob scale // lprior is required by priorsense::powerscale_sensitivity() real lprior = normal_lpdf(alpha | 0, 1) + normal_lpdf(nu | -1, 1); vector[n] log_lik; array[n] int pred_choice; for (i in 1:n) { log_lik[i] = log_mix(pi_hat, bernoulli_logit_lpmf(h[i] | 0.0), bernoulli_logit_lpmf(h[i] | alpha)); if (bernoulli_rng(pi_hat)) pred_choice[i] = bernoulli_rng(0.5); else pred_choice[i] = bernoulli_rng(theta); } } &quot; write_stan_file(single_mixture_stan, dir = &quot;stan/&quot;, basename = &quot;ch8_mixture_single.stan&quot;) ## [1] &quot;/Users/au209589/Dropbox/Teaching/AdvancedCognitiveModeling23_book/stan/ch8_mixture_single.stan&quot; mod_single &lt;- cmdstan_model( &quot;stan/ch8_mixture_single.stan&quot; ) 9.4.3 Data We use the simulated matching-pennies data introduced in earlier chapters, selecting the agent with rate 0.8 and noise 0.1. This gives us a ground truth against which to assess recovery: \(	heta = 0.8\), \(\pi = 0.1\). d &lt;- read_csv(here(&quot;simdata&quot;, &quot;04_randomnoise.csv&quot;), show_col_types = FALSE) dd &lt;- d |&gt; dplyr::filter(true_rate == 0.8, true_noise == 0.1) data &lt;- list(n = nrow(dd), h = as.integer(dd$choice)) cat(&quot;Trials:&quot;, data$n, &quot;| Proportion &#39;1&#39;:&quot;, round(mean(data$h), 3), &quot;
&quot;) ## Trials: 120 | Proportion &#39;1&#39;: 0.775 9.4.4 Fitting with Pathfinder Initialisation Mixture model posteriors can have multimodal or ridge-shaped geometry (see Section 6). Pathfinder — a multi-path variational approximation — provides stable starting points and avoids the Uniform(−2, 2) default initialisation that often fails when parameters are on very different scales or interact. If Pathfinder itself fails (e.g., because the variational approximation diverges near the ridge), the fallback must not be NULL. Passing NULL to init triggers Stan’s Uniform(−2, 2) default, which places chains at random points that may lie far from the high-probability region and immediately generate divergent transitions. Instead we define an explicit per-chain jittered initialisation centred on the prior medians: \(\alpha = 0\) (i.e., \(	heta = 0.5\)) and \(
u = -1\) (i.e., \(\pi \approx 0.27\)). A small Gaussian jitter of SD 0.1 ensures chains start at distinct points, which is necessary for \(\hat{R}\) to be meaningful. single_fit_file &lt;- &quot;simmodels/ch8_single_mixture.RDS&quot; if (regenerate_simulations || !file.exists(single_fit_file)) { # Explicit per-chain jittered initialisation at prior medians. # Used as Pathfinder fallback; safe for ridge-shaped posteriors. safe_init &lt;- lapply(seq_len(4), function(i) list( alpha = rnorm(1, 0.0, 0.1), nu = rnorm(1, -1.0, 0.1) )) init_pf &lt;- tryCatch( mod_single$pathfinder( data = data, seed = 8, num_paths = 4, refresh = 0 ), error = function(e) { message(&quot;Pathfinder failed — falling back to jittered prior-centre initialisation.&quot;) safe_init } ) fit_single &lt;- mod_single$sample( data = data, init = init_pf, seed = 8, chains = 4, parallel_chains = 4, iter_warmup = 1000, iter_sampling = 2000, refresh = 500 ) fit_single$save_object(single_fit_file) } else { fit_single &lt;- readRDS(single_fit_file) } fit_single$summary(c(&quot;alpha&quot;, &quot;nu&quot;, &quot;theta&quot;, &quot;pi_hat&quot;)) ## # A tibble: 4 × 10 ## variable mean median sd mad q5 q95 rhat ess_bulk ess_tail ## &lt;chr&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; ## 1 alpha 1.58 1.52 0.417 0.380 1.00 2.36 1.00 3114. 2450. ## 2 nu -1.55 -1.48 0.745 0.734 -2.87 -0.465 1.00 2943. 2738. ## 3 theta 0.821 0.821 0.0547 0.0562 0.732 0.914 1.00 3114. 2450. ## 4 pi_hat 0.198 0.185 0.104 0.109 0.0536 0.386 1.00 2943. 2738. 9.4.5 Geometry Diagnostics draws_single &lt;- as_draws_df(fit_single$draws()) # Required diagnostic thresholds (cheatsheet): # Divergences = 0 | R-hat &lt; 1.01 | Bulk &amp; Tail ESS &gt; 400 | E-BFMI &gt; 0.2 diag &lt;- fit_single$diagnostic_summary() cat(&quot;Divergences:&quot;, sum(diag$num_divergent), &quot;
&quot;) ## Divergences: 0 cat(&quot;Max R-hat: &quot;, round(max(fit_single$summary()$rhat, na.rm = TRUE), 4), &quot;
&quot;) ## Max R-hat: 1.0017 cat(&quot;Min ESS: &quot;, round(min(fit_single$summary()$ess_bulk, na.rm = TRUE)), &quot;
&quot;) ## Min ESS: 2861 # Trace plots for the two sampled parameters mcmc_trace(draws_single, pars = c(&quot;alpha&quot;, &quot;nu&quot;)) + ggtitle(&quot;Trace plots: logit-scale parameters&quot;) + scale_colour_viridis_d(option = &quot;mako&quot;, begin = 0.15, end = 0.85, guide = &quot;none&quot;) # Pairwise geometry on the probability scale — reveals ridge if present mcmc_pairs( fit_single$draws(), pars = c(&quot;theta&quot;, &quot;pi_hat&quot;), off_diag_fun = &quot;scatter&quot;, off_diag_args = list(size = 0.3, alpha = 0.2) ) + labs(title = &quot;Posterior geometry: bias × noise&quot;, subtitle = &quot;A ridge along the aliasing manifold is expected for binary data (see Section 6)&quot;) ## NULL 9.5 Validation: Simulation-Based Calibration SBC simultaneously certifies two properties. When rank statistics are uniform, the sampler is computationally unbiased (calibration). The joint distribution of true values and posterior summaries across all SBC datasets provides parameter recovery — the same information conveyed by a recovery grid, but derived from a principled random draw over the full prior rather than a hand-chosen set of grid points. 9.5.1 Generator and Backend Why SBC for mixture models specifically? Mixture posteriors are often ridge-shaped or multimodal, which means the sampler can fail silently — producing low divergences but biased posteriors. SBC’s rank-uniformity test catches this structural failure that standard diagnostics miss. sbc_gen_fn &lt;- function() { # Draw from prior (logit scale — must match Stan parameter names exactly) alpha_true &lt;- rnorm(1, 0, 1) nu_true &lt;- rnorm(1, -1, 1) theta_true &lt;- plogis(alpha_true) pi_true &lt;- plogis(nu_true) n &lt;- 120 component &lt;- rbinom(n, 1, pi_true) h &lt;- as.integer(ifelse( component == 1, rbinom(n, 1, 0.5), rbinom(n, 1, theta_true) )) list( variables = list(alpha = alpha_true, nu = nu_true), generated = list(n = n, h = h) ) } sbc_generator &lt;- SBC::SBC_generator_function(sbc_gen_fn) sbc_backend &lt;- SBC::SBC_backend_cmdstan_sample( mod_single, chains = 2, iter_warmup = 500, iter_sampling = 1000, refresh = 0, show_messages = FALSE ) sbc_file &lt;- &quot;simmodels/ch8_sbc_results.RDS&quot; if (regenerate_simulations || !file.exists(sbc_file)) { future::plan(future::multisession, workers = max(1, parallel::detectCores() - 2)) # S = 1000 certifies the rank statistic at the 95 % level. # For development, reduce to 200. sbc_datasets &lt;- SBC::generate_datasets(sbc_generator, n_sims = 1000) sbc_results &lt;- SBC::compute_SBC(sbc_datasets, sbc_backend) future::plan(future::sequential) saveRDS(sbc_results, sbc_file) } else { sbc_results &lt;- readRDS(sbc_file) } 9.5.2 Calibration: ECDF-Difference Plots The primary calibration diagnostic is the ECDF-difference plot (Säilynoja et al. 2022). A well-calibrated sampler produces rank statistics that are uniform on \(\{0, 1, \ldots, S\}\), so the ECDF should fall along the horizontal zero line. Deviations outside the 95 % envelope indicate structural bias or over/underconfidence. SBC::plot_ecdf_diff(sbc_results, variables = c(&quot;alpha&quot;, &quot;nu&quot;)) + labs(title = &quot;SBC calibration: ECDF-difference plots&quot;, subtitle = &quot;Deviations outside the grey band indicate a miscalibrated sampler&quot;) + theme(strip.background = element_rect(fill = &quot;grey95&quot;, colour = NA), strip.text = element_text(face = &quot;bold&quot;)) SBC::plot_rank_hist(sbc_results, variables = c(&quot;alpha&quot;, &quot;nu&quot;)) + labs(title = &quot;SBC calibration: rank histograms&quot;, subtitle = &quot;U-shape → overconfident; hump → underconfident; skew → biased&quot;) + theme(strip.background = element_rect(fill = &quot;grey95&quot;, colour = NA), strip.text = element_text(face = &quot;bold&quot;)) 9.5.3 Parameter Recovery The stats component of the SBC output contains the simulated_value (the true prior draw) alongside posterior summaries for each simulation. Plotting posterior mean against true value directly provides the recovery assessment — no separate grid-based recovery study is required. recovery_df &lt;- sbc_results$stats |&gt; dplyr::filter(variable %in% c(&quot;alpha&quot;, &quot;nu&quot;)) |&gt; dplyr::mutate( param_label = dplyr::recode(variable, alpha = &quot;alpha (logit bias)&quot;, nu = &quot;nu (logit noise)&quot; ), # Calibration coverage: does the 95 % CrI contain the truth? covered_95 = simulated_value &gt;= q5 &amp; simulated_value &lt;= q95 ) # Coverage summary recovery_df |&gt; dplyr::group_by(param_label) |&gt; dplyr::summarise( coverage_95 = mean(covered_95), rmse = sqrt(mean((mean - simulated_value)^2)), .groups = &quot;drop&quot; ) |&gt; print() ## # A tibble: 2 × 3 ## param_label coverage_95 rmse ## &lt;chr&gt; &lt;dbl&gt; &lt;dbl&gt; ## 1 alpha (logit bias) 0.893 0.403 ## 2 nu (logit noise) 0.897 0.953 # Recovery scatter: posterior mean vs. true value ggplot(recovery_df, aes(x = simulated_value, y = mean)) + geom_point(aes(colour = covered_95), size = 0.7, alpha = 0.5) + geom_linerange(aes(ymin = q5, ymax = q95, colour = covered_95), linewidth = 0.25, alpha = 0.3) + geom_abline(intercept = 0, slope = 1, linetype = &quot;dashed&quot;, colour = &quot;black&quot;, linewidth = 0.8) + facet_wrap(~param_label, scales = &quot;free&quot;) + scale_colour_manual( values = c(&quot;TRUE&quot; = &quot;#2166AC&quot;, &quot;FALSE&quot; = &quot;#D6604D&quot;), name = &quot;95 % CrI covers truth&quot; ) + labs( title = &quot;Parameter recovery from SBC simulations&quot;, subtitle = &quot;Each point is one SBC dataset; dashed line = perfect recovery (y = x)&quot;, x = &quot;True value (prior draw)&quot;, y = &quot;Posterior mean&quot; ) + theme( legend.position = &quot;top&quot;, strip.background = element_rect(fill = &quot;grey95&quot;, colour = NA), strip.text = element_text(face = &quot;bold&quot;), panel.grid.major = element_line(colour = &quot;grey92&quot;, linetype = &quot;dotted&quot;) ) Recovery should be unbiased across the full prior range. The fraction of 95 % credible intervals covering the truth should be close to 0.95. Systematic deviations — for instance, the noise parameter \(
u\) recovering poorly near \(
u \approx -2\) (i.e., \(\pi \approx 0.12\)) — would indicate that 120 trials provide insufficient information to distinguish very low noise from zero noise, a legitimate finding about the experimental design, not a modelling failure. 9.6 Identifiability: The Bernoulli Aliasing Problem 9.6.1 The Algebraic Constraint Why prove identifiability analytically before checking it empirically? The aliasing manifold exists regardless of sample size or model quality. No amount of data or better priors can break a fundamental algebraic degeneracy. Understanding the constraint analytically tells us exactly what additional information (RT, condition manipulation) would be required — rather than leaving us puzzled when LOO shows no preference. For a single binary trial the probability of observing \(y_i = 1\) under the bias–noise mixture is: \[ P(y_i = 1) = (1 - \pi)\,	heta + \pi \cdot 0.5 = 	heta - \pi(	heta - 0.5). 	ag{7} \] This depends on \((	heta, \pi)\) only through the linear combination \(	heta_{	ext{eff}} = (1-\pi)	heta + 0.5\pi\). For i.i.d. binary observations, the entire dataset carries information only about this one-dimensional quantity. Consequently, infinitely many \((	heta, \pi)\) pairs are observationally equivalent: for any fixed observed proportion \( ar{y}\), the set \[  igl\{(	heta, \pi) : (1-\pi)\,	heta + 0.5\,\pi =  ar{y} igr\} 	ag{8} \] is a curve in parameter space, and the posterior will be smeared along this curve. This is the aliasing manifold. The mixture model is not wrong — it is simply not identified from the marginal binary likelihood alone. The bias and noise parameters are individually interpretable and scientifically meaningful; the data just cannot separate them without additional structure (e.g., trial-level covariates, joint RT and accuracy modelling, or experimental manipulations of the noise rate). 9.6.2 Visualising the Posterior Ridge draws_prob &lt;- as_draws_df(fit_single$draws()) |&gt; dplyr::select(theta, pi_hat) obs_prop &lt;- mean(data$h) # Aliasing manifold: all (theta, pi) consistent with observed proportion pi_grid &lt;- seq(0, 0.95, by = 0.002) theta_mani &lt;- (obs_prop - 0.5 * pi_grid) / (1 - pi_grid) manifold &lt;- tibble(pi_hat = pi_grid, theta = theta_mani) |&gt; dplyr::filter(theta &gt;= 0, theta &lt;= 1) ggplot(draws_prob, aes(x = pi_hat, y = theta)) + geom_point(alpha = 0.06, size = 0.5, colour = &quot;#2166AC&quot;) + geom_line(data = manifold, colour = &quot;#D6604D&quot;, linewidth = 1.0) + annotate(&quot;text&quot;, x = 0.45, y = 0.92, colour = &quot;#D6604D&quot;, hjust = 0, label = expression(hat(theta)[eff] == bar(y))) + labs( title = &quot;Posterior geometry and the aliasing manifold&quot;, subtitle = &quot;Red curve: all (π, θ) pairs consistent with the observed choice proportion&quot;, x = expression(pi ~ &quot;(noise weight)&quot;), y = expression(theta ~ &quot;(bias)&quot;) ) + coord_cartesian(xlim = c(0, 0.6), ylim = c(0.5, 1.0)) The posterior concentrates along the red aliasing manifold rather than converging to a point. This is not a sampling pathology — it is the correct Bayesian representation of what the data actually contain. The prior does provide some regularisation (the posterior does not extend to the full manifold), but with 120 binary observations and diffuse priors, the two parameters remain substantially correlated. 9.6.3 Why the RT Case is Different Recall from Section 1 that the RT mixture was visually transparent. The reason is that the two components have different likelihoods for the same observation value. A 400 ms response is extremely unlikely under the uniform lapse process but highly probable under the log-normal deliberate process. This trial-level likelihood contrast provides information about \(z_i\) for each observation, breaking the aliasing. With binary choices, both the biased process (at some \(	heta\)) and the random process (at 0.5) assign non-zero probability to both outcomes, so the aliasing cannot be broken by observation values alone. This comparison motivates a practical principle: if you want a mixture model’s components to be individually identified, ensure that the components are distinguishable at the level of individual observations, not merely at the level of marginal statistics. Two strategies accomplish this in practice. Strategy A: Joint modelling of complementary outcome types. If reaction time \(rt_i\) is observed alongside each binary choice \(y_i\), the per-trial joint likelihood becomes: \[ p(y_i, rt_i) = (1-\pi)\; p_{	ext{bias}}(y_i \mid 	heta)\; p_{	ext{LN}}(rt_i \mid \mu, \sigma) \;+\; \pi\; p_{	ext{rand}}(y_i \mid 0.5)\; p_{	ext{unif}}(rt_i \mid a, b). 	ag{8a} \] Because \(p_{	ext{LN}}(rt_i \mid \mu, \sigma) / p_{	ext{unif}}(rt_i \mid a, b)\) varies continuously with \(rt_i\), every observation now provides direct evidence about \(z_i\). A short RT carries high likelihood under the log-normal deliberate component and low likelihood under the uniform lapse component, or vice versa for an unusually long RT. The aliasing manifold collapses to a point: the two-dimensional parameter space \((	heta, \pi)\) is identified by the joint data stream, not just the marginal choice proportion. Strategy B: Experimental manipulation of the noise rate. Suppose participants complete a single-task block (\(c_i = 0\)) and a dual-task block (\(c_i = 1\)), where the additional cognitive load is expected to increase lapse frequency but leave the deliberate bias intact. We model \(\pi\) as a function of condition while holding \(	heta\) constant: \[ 
u_i = \gamma_0 + \gamma_1 c_i, \qquad \pi_i = 	ext{logit}^{-1}(
u_i). 	ag{8b} \] The aliasing constraint now applies separately within each condition: \[ (1 - \pi_0)\,	heta + 0.5\,\pi_0 =  ar{y}_0, \qquad (1 - \pi_1)\,	heta + 0.5\,\pi_1 =  ar{y}_1. 	ag{8c} \] These are two linear equations in the three unknowns \((	heta, \pi_0, \pi_1)\) — or equivalently \((	heta, \gamma_0, \gamma_1)\). If \(\pi_0 
e \pi_1\) (i.e., if the dual-task manipulation actually changes the noise rate), the two manifolds intersect at a unique point and all three parameters are identified. The identifiability here does not require RT data at all: the experimental design does the work by breaking the single-condition degeneracy. 9.7 Prior Sensitivity Analysis Section 6 established analytically that the binary likelihood cannot separate \(	heta\) and \(\pi\): the data constrain only \(	heta_{	ext{eff}} = (1-\pi)	heta + 0.5\pi\). A direct corollary is that the posterior for at least one of the individual parameters must be sensitive to the prior. priorsense::powerscale_sensitivity() quantifies this sensitivity without refitting the model. It uses Pareto-smoothed importance sampling to evaluate the perturbed posterior: \[ p_{\alpha, eta}(	heta, \pi \mid y) \propto p(y \mid 	heta, \pi)^{\alpha}\; p(	heta, \pi)^{ eta}, 	ag{11} \] where \(\alpha\) and \( eta\) are power-scaling factors. Sensitivity to the prior corresponds to varying \( eta\) while holding \(\alpha = 1\); sensitivity to the likelihood corresponds to varying \(\alpha\) while holding \( eta = 1\). The summary statistic \(\hat{\psi}\) measures how much the posterior mean shifts (in units of posterior SD) as the scaling factor departs from 1. Values above \(\approx 0.05\) indicate non-negligible sensitivity. The priorsense workflow requires a lprior variable in the Stan model’s generated quantities block, which accumulates the log prior density. This was added to the single-agent Stan model in §4.2 and will be added to the multilevel model in §8.2. The powerscale_sensitivity() call then reads lprior as the prior contribution and uses log_lik as the likelihood contribution. Why expect high sensitivity for the noise parameter? Section 6 showed algebraically that binary i.i.d. data constrain only θ_eff = (1-π)θ + 0.5π. The noise weight π therefore receives almost no direct information from the data — its posterior is largely proportional to its prior. A high ψ̂ for ν is not a model failure; it is the quantitative fingerprint of this degeneracy. # powerscale_sensitivity works with CmdStanFit objects via the posterior package. # It reads &#39;lprior&#39; and &#39;log_lik&#39; from generated quantities automatically. sensitivity &lt;- priorsense::powerscale_sensitivity( fit_single, variable = c(&quot;alpha&quot;, &quot;nu&quot;) ) print(sensitivity) ## Sensitivity based on cjs_dist ## Prior selection: all priors ## Likelihood selection: all data ## ## variable prior likelihood diagnosis ## alpha 0.140 0.063 potential prior-data conflict ## nu 0.104 0.027 potential strong prior / weak likelihood # Density deformation under power-scaling shows which parameters are affected. priorsense::powerscale_plot_dens(fit_single, variables = c(&quot;alpha&quot;, &quot;nu&quot;)) + labs( title = &quot;Prior sensitivity: power-scaled posterior densities&quot;, subtitle = expression( &quot;Stronger deformation = greater dependence on the prior&quot; ) ) + theme( strip.background = element_rect(fill = &quot;grey95&quot;, colour = NA), strip.text = element_text(face = &quot;bold&quot;), legend.position = &quot;bottom&quot; ) The expected pattern is instructive: \(\hat{\psi}\) for \(
u\) (noise, logit scale) should be substantially higher than \(\hat{\psi}\) for \(\alpha\) (bias, logit scale). This is the quantitative signature of the aliasing manifold. The bias \(	heta\) is constrained by the data through \(	heta_{	ext{eff}} \approx  ar{y}\), so the posterior mean of \(\alpha\) is relatively stable under prior perturbation. The noise weight \(\pi\), by contrast, receives almost no direct information from binary i.i.d. data, so its posterior is nearly proportional to its prior. A strong \(\hat{\psi}\) for \(
u\) is therefore not a modelling failure — it is an empirical confirmation of the §6 identifiability analysis and should be reported alongside it. Workflow note. If powerscale_sensitivity() returns a Pareto-\(\hat{k}\) warning for the prior scaling direction, it signals that the prior and likelihood are in strong conflict — the perturbed posterior is too far from the fitted posterior to be reliably approximated by importance sampling. In that case, refit with scaled priors explicitly. For the noise parameter under typical experimental conditions this warning is unlikely because the prior is doing most of the work; conflict warnings are more characteristic of well-identified parameters with informative priors. 9.8 Posterior Predictive Checks and LOO 9.8.1 Posterior Predictive Checks Posterior predictive draws are computed in the generated quantities block and extracted directly from the fitted object. This avoids the manual simulation loop in the original chapter, which re-implemented in R what Stan already computed. # S x n matrix of posterior predictive choices (0/1) yrep &lt;- fit_single$draws(&quot;pred_choice&quot;, format = &quot;matrix&quot;) y &lt;- as.integer(data$h) # PPC 1: proportion of &quot;1&quot; choices p_mean &lt;- bayesplot::ppc_stat( y = y, yrep = yrep, stat = &quot;mean&quot; ) + labs(title = &quot;PPC: proportion of right choices&quot;, x = &quot;Mean choice&quot;) # PPC 2: mean run length — sensitive to serial structure obs_run &lt;- mean(rle(y)$lengths) pred_run &lt;- apply(yrep, 1, function(x) mean(rle(x)$lengths)) p_run &lt;- ggplot(tibble(run = pred_run), aes(x = run)) + geom_histogram(aes(y = after_stat(density)), bins = 40, fill = &quot;#2166AC&quot;, alpha = 0.7) + geom_vline(xintercept = obs_run, colour = &quot;#D6604D&quot;, linewidth = 1.0, linetype = &quot;dashed&quot;) + annotate(&quot;text&quot;, x = obs_run + 0.05, y = Inf, vjust = 1.5, label = &quot;Observed&quot;, colour = &quot;#D6604D&quot;, size = 3.5, hjust = 0) + labs(title = &quot;PPC: mean run length&quot;, subtitle = &quot;Sensitive to sequential autocorrelation the mean cannot detect&quot;, x = &quot;Mean run length&quot;, y = &quot;Density&quot;) p_mean / p_run Interpretation: If the run-length check fails (observed value in the tail of the predictive distribution) while the mean check passes, the data contain sequential dependence that a fully i.i.d. mixture model cannot reproduce. In that case, consider a hidden Markov model with Markov-dependent \(z_i\) (Section 10). 9.8.2 PSIS-LOO and Pareto-\(\hat{k}\) Diagnostics log_lik_mat &lt;- fit_single$draws(&quot;log_lik&quot;, format = &quot;matrix&quot;) r_eff &lt;- loo::relative_eff(exp(log_lik_mat), chain_id = rep(1:4, each = 2000)) loo_single &lt;- loo::loo(log_lik_mat, r_eff = r_eff, save_psis = TRUE) print(loo_single) ## ## Computed from 8000 by 120 log-likelihood matrix. ## ## Estimate SE ## elpd_loo -65.0 5.3 ## p_loo 0.9 0.1 ## looic 130.0 10.5 ## ------ ## MCSE of elpd_loo is 0.0. ## MCSE and ESS estimates assume MCMC draws (r_eff in [0.9, 0.9]). ## ## All Pareto k estimates are good (k &lt; 0.7). ## See help(&#39;pareto-k-diagnostic&#39;) for details. plot(loo_single, label_points = TRUE, main = &quot;PSIS-LOO Pareto-k diagnostics&quot;) Pareto-\(\hat{k}\) values above 0.7 indicate observations for which the full-data posterior is a poor approximation to the leave-one-out posterior. In a mixture model, such observations are often concentrated near \(y = 0.5\) (where the biased and random components are most confounded) or in long runs of the same choice (which the i.i.d. model cannot anticipate). 9.8.3 LOO-PIT For continuous outcomes, LOO-PIT values should be uniform. For binary outcomes the CDF is a step function, so the standard PIT is discrete and requires randomisation to achieve uniformity. The rstantools::loo_pit()` function applies this randomisation automatically. psis_obj &lt;- loo_single$psis_object lw &lt;- weights(psis_obj, log = TRUE, normalize = TRUE) # draws × obs yrep_int &lt;- matrix(as.integer(yrep), nrow = nrow(yrep)) pit_vals &lt;- rstantools::loo_pit(object = yrep_int, y = y, lw = lw) 9.9 Multilevel Mixture Model 9.9.1 Generative Model When data come from \(J\) participants, we extend the model hierarchically. Each participant \(j\) has their own bias \(\alpha_j\) and noise \(
u_j\), which are drawn from a bivariate normal population distribution: \[  egin{pmatrix} \alpha_j \ 
u_j \end{pmatrix} =  egin{pmatrix} \mu_\alpha \ \mu_
u \end{pmatrix} + \mathbf{L}\, oldsymbol{z}_j, \qquad  oldsymbol{z}_j \sim 	ext{Normal}_2(\mathbf{0}, \mathbf{I}), 	ag{9} \] where \(\mathbf{L} = 	ext{diag}(	au) \cdot \mathbf{L}_\Omega\) is the Cholesky factor of the parameter covariance matrix, \(	au\) is the vector of population standard deviations, and \(\mathbf{L}_\Omega\) is the Cholesky factor of the correlation matrix. This is the non-centred parameterisation (NCP) introduced in Chapter 6. Priors: \[ \mu_\alpha \sim 	ext{Normal}(0, 1), \qquad \mu_
u \sim 	ext{Normal}(-1, 0.5), \] \[ 	au_k \sim 	ext{Half-Normal}(0, 0.3), \quad k = 1, 2, \qquad \mathbf{L}_\Omega \sim 	ext{LKJ}(2). \] Per-trial likelihood (same correction as in Section 4.1): \[ y_{t,j} \sim \log	ext{-mix}\! igl(	ext{logit}^{-1}(
u_j),\; 	ext{Bern}(0.5),\; 	ext{Bern}(	ext{logit}^{-1}(\alpha_j)) igr). 	ag{10} \] 9.9.2 Stan Code multilevel_mixture_stan &lt;- &quot; data { int&lt;lower=1&gt; trials; int&lt;lower=1&gt; agents; array[trials, agents] int&lt;lower=0, upper=1&gt; h; } parameters { real muA; // population mean bias (logit) real muN; // population mean noise (logit) vector&lt;lower=0&gt;[2] tau; // population SDs: [bias, noise] matrix[2, agents] z_IDs; // standardised individual offsets cholesky_factor_corr[2] L_Omega; // Cholesky of correlation matrix } transformed parameters { // Non-centred: individual offsets on the logit scale matrix[agents, 2] IDs = (diag_pre_multiply(tau, L_Omega) * z_IDs)&#39;; } model { target += normal_lpdf(muA | 0, 1); target += normal_lpdf(muN | -1, 0.5); // tau is declared vector&lt;lower=0&gt;[2], so Stan applies the log Jacobian // of the log transform automatically. The truncation normalising constant // is already absorbed into the unconstrained parameterisation; manually // subtracting normal_lccdf() would add unnecessary AD nodes for a // constant that cancels. Vectorised call covers both SD elements. target += normal_lpdf(tau | 0, 0.3); target += lkj_corr_cholesky_lpdf(L_Omega | 2); target += std_normal_lpdf(to_vector(z_IDs)); // Per-agent, per-trial mixture likelihood (correct loop structure). // Both components use bernoulli_logit_lpmf for scale consistency: // logit(0.5) = 0.0, so the random component is bernoulli_logit_lpmf(h | 0.0). for (i in 1:agents) { real noise_i = inv_logit(muN + IDs[i, 2]); real alpha_i = muA + IDs[i, 1]; for (t in 1:trials) target += log_mix(noise_i, bernoulli_logit_lpmf(h[t, i] | 0.0), bernoulli_logit_lpmf(h[t, i] | alpha_i)); } } generated quantities { // Population-level summaries real&lt;lower=0, upper=1&gt; pop_bias = inv_logit(muA); real&lt;lower=0, upper=1&gt; pop_noise = inv_logit(muN); corr_matrix[2] Omega = multiply_lower_tri_self_transpose(L_Omega); real bias_noise_corr = Omega[1, 2]; // lprior is required by priorsense::powerscale_sensitivity(). // Must mirror every term in the model block exactly. real lprior = normal_lpdf(muA | 0, 1) + normal_lpdf(muN | -1, 0.5) + normal_lpdf(tau | 0, 0.3) + lkj_corr_cholesky_lpdf(L_Omega | 2) + std_normal_lpdf(to_vector(z_IDs)); // Individual parameters array[agents] real&lt;lower=0, upper=1&gt; agent_bias; array[agents] real&lt;lower=0, upper=1&gt; agent_noise; // Per-trial log-lik (needed for LOO and priorsense) array[trials, agents] real log_lik; for (i in 1:agents) { real alpha_i = muA + IDs[i, 1]; real noise_i = inv_logit(muN + IDs[i, 2]); agent_bias[i] = inv_logit(alpha_i); agent_noise[i] = noise_i; for (t in 1:trials) log_lik[t, i] = log_mix(noise_i, bernoulli_logit_lpmf(h[t, i] | 0.0), bernoulli_logit_lpmf(h[t, i] | alpha_i)); } } &quot; write_stan_file(multilevel_mixture_stan, dir = &quot;stan/&quot;, basename = &quot;ch8_mixture_multilevel.stan&quot;) ## [1] &quot;/Users/au209589/Dropbox/Teaching/AdvancedCognitiveModeling23_book/stan/ch8_mixture_multilevel.stan&quot; mod_multi &lt;- cmdstan_model( &quot;stan/ch8_mixture_multilevel.stan&quot; ) 9.9.3 Simulating Multilevel Data set.seed(801) n_agents &lt;- 30 n_trials &lt;- 120 # Population parameters (logit scale) muA_true &lt;- qlogis(0.75) # mean bias ≈ 0.75 muN_true &lt;- qlogis(0.12) # mean noise ≈ 0.12 tauA_true &lt;- 0.50 tauN_true &lt;- 0.40 # Individual parameters (logit scale) alpha_j &lt;- rnorm(n_agents, muA_true, tauA_true) nu_j &lt;- rnorm(n_agents, muN_true, tauN_true) # Generate choice matrix [trials x agents] h_matrix &lt;- matrix(NA_integer_, nrow = n_trials, ncol = n_agents) for (j in seq_len(n_agents)) { theta_j &lt;- plogis(alpha_j[j]) pi_j &lt;- plogis(nu_j[j]) for (t in seq_len(n_trials)) { h_matrix[t, j] &lt;- if (rbinom(1, 1, pi_j) == 1) rbinom(1, 1, 0.5) else rbinom(1, 1, theta_j) } } data_multi &lt;- list( trials = n_trials, agents = n_agents, h = h_matrix ) # True individual parameters for later recovery plots true_params &lt;- tibble( agent = seq