&quot;) ## Population bias (prob scale): 0.75 cat(&quot;Population noise (prob scale):&quot;, round(plogis(muN_true), 3), &quot;
&quot;) ## Population noise (prob scale): 0.12 9.9.4 Fitting The same Pathfinder-with-safe-fallback pattern from §4.4 applies here, with one important difference: the multilevel model has additional structure that the fallback initialisation must respect. Setting tau to a small positive value (rather than drawing from the full half-normal prior) avoids starting near the funnel geometry. Setting z_IDs to near-zero ensures all individual parameters begin at their population means. Setting L_Omega to the identity matrix provides a neutral starting correlation. All values are jittered slightly across chains. multi_fit_file &lt;- &quot;simmodels/ch8_multilevel_mixture.RDS&quot; if (regenerate_simulations || !file.exists(multi_fit_file)) { # Explicit per-chain jittered initialisation at prior-centre values. # tau near zero avoids the NCP funnel; z_IDs = 0 starts all agents # at the population mean; L_Omega = I provides neutral correlation. safe_init_m &lt;- lapply(seq_len(4), function(i) list( muA = rnorm(1, 0.0, 0.1), muN = rnorm(1, -1.0, 0.1), tau = abs(rnorm(2, 0.1, 0.02)), z_IDs = matrix(rnorm(2 * n_agents, 0, 0.05), 2, n_agents), L_Omega = diag(2) )) init_pf_m &lt;- tryCatch( mod_multi$pathfinder(data = data_multi, seed = 801, num_paths = 4, refresh = 0), error = function(e) { message(&quot;Pathfinder failed — falling back to jittered prior-centre initialisation.&quot;) safe_init_m } ) fit_multi &lt;- mod_multi$sample( data = data_multi, init = init_pf_m, seed = 801, chains = 4, parallel_chains = 4, iter_warmup = 1000, iter_sampling = 2000, refresh = 500 ) fit_multi$save_object(multi_fit_file) } else { fit_multi &lt;- readRDS(multi_fit_file) } fit_multi$summary(c(&quot;pop_bias&quot;, &quot;pop_noise&quot;, &quot;tau&quot;, &quot;bias_noise_corr&quot;)) ## # A tibble: 5 × 10 ## variable mean median sd mad q5 q95 rhat ess_bulk ess_tail ## &lt;chr&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; &lt;dbl&gt; ## 1 pop_bi